examples.bad:
Button("Pay") {
  Task { try await viewModel.pay() } // ❌ No loading state
}

examples.good:
Button("Pay") {
  Task {
    viewModel.isLoading = true
    defer { viewModel.isLoading = false }
    try await viewModel.pay()
  }
}
if viewModel.isLoading { ProgressView() }

examples.bad:
Task {
  try? await viewModel.transfer() // ❌ Errors are silently ignored
}

examples.good:
Task {
  do {
    try await viewModel.transfer()
  } catch {
    errorMessage = error.localizedDescription
    showError = true
  }
}
